const fs = require('fs');
const path = require('path');
const vaultPath = 'C:/Users/manaz/Desktop/JobFilter/JobFilterV1/Obsidian_Memory/Obsidian_Vault';
const runsRoot = path.join(vaultPath, 'JobFilter', 'Agent Runs');
const outcomesDir = path.join(vaultPath, 'JobFilter', 'Outcomes');
const resolved = new Set();
if (fs.existsSync(outcomesDir)) {
  for (const f of fs.readdirSync(outcomesDir)) {
    if (f.endsWith('.md')) resolved.add(f.replace(/\.md$/, ''));
  }
}
const now = Date.now();
const dayMs = 86400000;
const leadAge = {};
if (fs.existsSync(runsRoot)) {
  for (const folder of fs.readdirSync(runsRoot)) {
    const folderPath = path.join(runsRoot, folder);
    if (!fs.statSync(folderPath).isDirectory()) continue;
    const folderDate = new Date(folder + 'T00:00:00Z').getTime();
    if (isNaN(folderDate) || now - folderDate > 21 * dayMs) continue;
    for (const f of fs.readdirSync(folderPath)) {
      if (!f.endsWith('.md')) continue;
      try {
        const body = fs.readFileSync(path.join(folderPath, f), 'utf-8');
        const matches = body.match(/\"id\"\s*:\s*\"([^\"]+)\"/g) || [];
        for (const m of matches) {
          const id = m.match(/\"id\"\s*:\s*\"([^\"]+)\"/)[1];
          if (!id || id.length > 80) continue;
          if (!leadAge[id]) leadAge[id] = { firstSeenAt: folderDate, lastSeenAt: folderDate };
          else leadAge[id].lastSeenAt = Math.max(leadAge[id].lastSeenAt, folderDate);
        }
      } catch {}
    }
  }
}
const buckets = { day3: [], day7: [], day14: [] };
for (const [id, ages] of Object.entries(leadAge)) {
  if (resolved.has(id.toLowerCase().replace(/[^a-z0-9]+/g, '-'))) continue;
  const days = Math.floor((now - ages.firstSeenAt) / dayMs);
  if (days === 3) buckets.day3.push(id);
  else if (days === 7) buckets.day7.push(id);
  else if (days === 14) buckets.day14.push(id);
}
const total = buckets.day3.length + buckets.day7.length + buckets.day14.length;
return [{ json: { buckets, total, resolved: resolved.size, scanned: Object.keys(leadAge).length } }];
